import{_ as a,j as e,p as t,at as i}from"./chunks/framework.CFWbLlrS.js";const k=JSON.parse('{"title":"@satorijs/adapter-kook","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/adapters/kook.md","filePath":"zh-CN/adapters/kook.md"}'),r={name:"zh-CN/adapters/kook.md"};function n(l,o,d,s,p,h){return e(),t("div",null,[...o[0]||(o[0]=[i('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /adapters/kook.md for this page in Markdown format</div><h1 id="satorijs-adapter-kook" tabindex="-1">@satorijs/adapter-kook <a class="header-anchor" href="#satorijs-adapter-kook" aria-label="Permalink to “@satorijs/adapter-kook”">​</a></h1><h2 id="接入方法" tabindex="-1">接入方法 <a class="header-anchor" href="#接入方法" aria-label="Permalink to “接入方法”">​</a></h2><ol><li>前往 <a href="https://developer.kookapp.cn/" target="_blank" rel="noreferrer">开发者平台</a>，选择「机器人」并点击「新建」</li><li>根据自身需要，在「机器人连接模式」中选择 Webhook 或 WebSocket 中的一种： <ul><li>如果是 Webhook，请记下页面中的 <code>token</code> 和 <code>verify_token</code>（请注意不要泄露），并作为机器人的配置项</li><li>如果是 WebSocket，则只需记录 <code>token</code>（请注意不要泄露）并作为机器人的配置项即可</li></ul></li></ol><h2 id="基础配置项" tabindex="-1">基础配置项 <a class="header-anchor" href="#基础配置项" aria-label="Permalink to “基础配置项”">​</a></h2><h3 id="options-protocol" tabindex="-1">options.protocol <a class="header-anchor" href="#options-protocol" aria-label="Permalink to “options.protocol”">​</a></h3><ul><li>可选值: http, ws</li></ul><p>要使用的协议类型。</p><h3 id="options-token" tabindex="-1">options.token <a class="header-anchor" href="#options-token" aria-label="Permalink to “options.token”">​</a></h3><ul><li>类型: <code>string</code></li></ul><p>机器人账户的令牌。</p><h3 id="options-endpoint" tabindex="-1">options.endpoint <a class="header-anchor" href="#options-endpoint" aria-label="Permalink to “options.endpoint”">​</a></h3><ul><li>类型: <code>string</code></li><li>默认值: <code>&#39;https://www.kookapp.cn/api/v3&#39;</code></li></ul><p>要请求的 API 网址。</p><h3 id="options-attachmode" tabindex="-1">options.attachMode <a class="header-anchor" href="#options-attachmode" aria-label="Permalink to “options.attachMode”">​</a></h3><ul><li>类型: <code>&#39;separate&#39; | &#39;mixed&#39; | &#39;card&#39;</code></li><li>默认值: <code>&#39;separate&#39;</code></li></ul><p>控制当尝试发送含有资源元素的消息时的行为。</p><ul><li><strong>separate:</strong> 每一个资源消息段，以及资源消息段之间的文本都将单独发送一条消息</li><li><strong>mixed:</strong> 当要发送的内容中含有多个资源消息段或资源消息段和文本的混合时，发送卡片消息；否则将单独发送资源消息段</li><li><strong>card:</strong> 当要发送的内容中含有资源消息段，则以卡片消息的形式发送</li></ul><h2 id="http-配置项" tabindex="-1">HTTP 配置项 <a class="header-anchor" href="#http-配置项" aria-label="Permalink to “HTTP 配置项”">​</a></h2><h3 id="options-verifytoken" tabindex="-1">options.verifyToken <a class="header-anchor" href="#options-verifytoken" aria-label="Permalink to “options.verifyToken”">​</a></h3><ul><li>类型: <code>string</code></li></ul><p>机器人账户的验证令牌。</p><h3 id="options-path" tabindex="-1">options.path <a class="header-anchor" href="#options-path" aria-label="Permalink to “options.path”">​</a></h3><ul><li>类型: <code>string</code></li><li>默认值: <code>&#39;/kook&#39;</code></li></ul><p>服务器监听的路径。</p>',25)])])}const f=a(r,[["render",n]]);export{k as __pageData,f as default};
